// In standard C++ sort (std::sort), if compare(A, B) returns true, A comes before B.
bool compareSegments(const Segment& A, const Segment& B) {
    // Rule 1: Compare n1
    if (A.n1 != B.n1) {
        // Prefer larger n1
        return A.n1 > B.n1;
    }
    // Rule 2: If n1 are equal, prefer smaller n0 (fewer trailing zeros)
    return A.n0 < B.n0;
}

