/// Computes (base^exp) % mod efficiently using modular exponentiation.
fn power(base: Int64, exp: Int64, mod: Int64): Int64 {
    var res: Int64 = 1
    var b: Int64 = base % mod
    var e: Int64 = exp

    while e > 0 {
        if (e % 2) == 1 {
            res = (res * b) % mod
        }
        b = (b * b) % mod
        e /= 2
    }
    res
}

struct Segment {
    n1: Int64 // Count of '1's
    n0: Int64 // Count of '0's
}

// Custom comparison function for sorting segments.
// Returns true if segA should come before segB (i.e., segA + segB > segB + segA lexicographically).
fn compare_segments(segA: Segment, segB: Segment): Bool {
    // Rule 1: Compare the count of leading ones (n1)
    if segA.n1 != segB.n1 {
        // More ones come first
        return segA.n1 > segB.n1
    }

    // Rule 2: n1 are equal. Compare the count of trailing zeros (n0).
    // If n1=k, we compare 0^a0 1^k 0^b0 vs 0^b0 1^k 0^a0.
    // A comes before B if 0^a0 1^k 0^b0 > 0^b0 1^k 0^a0.
    // This happens if a0 < b0 (a shorter zero run means the next '1' appears sooner, yielding a larger number).
    if segA.n0 != segB.n0 {
        return segA.n0 < segB.n0
    }

    // If both n1 and n0 are equal, order doesn't matter.
    return false // False means they are equivalent in order
}


